/* Suggested markup: <div class="uiwiki-tracking-word-dossier" tabindex="0"><span>Tracking Word Dossier</span></div> */
.uiwiki-tracking-word-dossier {
  display: grid;
  place-items: center;
  min-height: 11rem;
  padding: 1.25rem;
  border: 1px solid #ececee;
  border-radius: 22px;
  background: #ffffff;
  color: #111111;
  font: 700 1rem/1.2 Inter, system-ui, sans-serif;
  box-shadow: 0 2px 16px rgba(0, 0, 0, 0.04);
  transition: transform 240ms cubic-bezier(.22, 1, .36, 1), box-shadow 240ms ease;
}
.uiwiki-tracking-word-dossier > span {
  padding: .75rem 1rem;
  border-radius: 999px;
  background: #53e8d4;
  animation: tracking_word_dossier 1.8s ease-in-out infinite alternate;
}
.uiwiki-tracking-word-dossier:hover,
.uiwiki-tracking-word-dossier:focus-visible {
  transform: translateY(-3px);
  box-shadow: 0 10px 28px rgba(0, 0, 0, 0.08);
}
@keyframes tracking_word_dossier {
  from { transform: translateY(0) scale(1); }
  to { transform: translateY(-4px) scale(1.025); }
}
@media (prefers-reduced-motion: reduce) {
  .uiwiki-tracking-word-dossier, .uiwiki-tracking-word-dossier > span { animation: none; transition: none; }
}
